//! P2 vision — per-frame object proposals from motion/background segmentation.
//!
//! Arbitrary video has no clean white background, so the sovereign (no-ML) detector here is
//! foreground-by-background-model: a per-pixel exponential-moving-average background, with the
//! foreground = pixels that deviate from it. Connected components on that mask become object
//! proposals (bbox, centroid, area, an appearance signature, and a silhouette crop), each tagged
//! with its genus (enclosed-hole count) for the reconstruction router.
//!
//! Honesty bound (PLAN.md): this detects *what moves / stands out*, geometrically — not semantic
//! classes. A static-camera clip segments cleanly; a moving camera makes the whole frame
//! "foreground" until the model re-adapts (flagged, not hidden).

use crate::frame::Frame;
use crate::motion::{estimate_global_motion, warp_luma, GlobalMotion};

/// Work resolution for the mask (small for speed; proposals are reported in normalised coords).
pub const WORK_W: usize = 256;

/// Downsample a frame's luma to `WORK_W` x (aspect) as f32 in [0,255].
fn downsample_luma(f: &Frame) -> (Vec<f32>, usize, usize) {
    let sw = f.width as usize;
    let sh = f.height as usize;
    let ww = WORK_W.min(sw.max(1));
    let wh = ((ww * sh) / sw.max(1)).max(1);
    let mut out = vec![0f32; ww * wh];
    let px = &f.rgb;
    for wy in 0..wh {
        let sy = wy * sh / wh;
        for wx in 0..ww {
            let sx = wx * sw / ww;
            let i = (sy * sw + sx) * 3;
            out[wy * ww + wx] = crate::simd::luma_u8(px[i], px[i + 1], px[i + 2]) as f32;
        }
    }
    (out, ww, wh)
}

/// Per-pixel EMA background model in luma.
pub struct BackgroundModel {
    w: usize,
    h: usize,
    mean: Vec<f32>,
    /// Frames absorbed; the model is warming up until `warmup` are seen.
    seen: u32,
    /// Previous frame's work-resolution luma, for global-motion estimation.
    prev: Vec<f32>,
}

impl BackgroundModel {
    pub fn new() -> Self {
        BackgroundModel {
            w: 0,
            h: 0,
            mean: Vec::new(),
            seen: 0,
            prev: Vec::new(),
        }
    }

    /// True once enough frames have been absorbed to trust the foreground mask.
    pub fn ready(&self, warmup: u32) -> bool {
        self.seen >= warmup
    }

    fn ensure(&mut self, w: usize, h: usize, init: &[f32]) {
        if self.w != w || self.h != h {
            self.w = w;
            self.h = h;
            self.mean = init.to_vec();
            self.seen = 1;
            self.prev = Vec::new();
        }
    }

    /// Update with a luma frame at the model's working resolution. `alpha` in (0,1] —
    /// small = slow background (sticky), large = fast adaptation. The per-pixel EMA is the
    /// SIMD-accelerated `simd::ema_update` kernel (f32x4 on wasm+simd128, identical scalar native).
    fn update(&mut self, luma: &[f32], w: usize, h: usize, alpha: f32) {
        self.ensure(w, h, luma);
        crate::simd::ema_update(&mut self.mean, luma, alpha);
        self.seen = self.seen.saturating_add(1);
    }
}

impl Default for BackgroundModel {
    fn default() -> Self {
        Self::new()
    }
}

/// Detection tuning.
#[derive(Debug, Clone)]
pub struct VisionConfig {
    /// Foreground threshold in luma units (|frame - bg| > thresh).
    pub fg_thresh: f32,
    /// Background EMA rate.
    pub bg_alpha: f32,
    /// Warmup frames before proposals are emitted.
    pub warmup: u32,
    /// Reject components smaller than this fraction of the frame.
    pub min_area_frac: f32,
    /// Reject components larger than this fraction (whole-frame "foreground" = camera moved).
    pub max_area_frac: f32,
    /// Morphological open/close radius (in work pixels).
    pub morph_r: i32,
    /// Compensate dominant global (camera) motion before differencing — turns a panning camera's
    /// whole-frame "foreground" back into residual object motion. Default on.
    pub compensate: bool,
    /// Reject proposals whose genus is not stable across downsampled mask scales (1-2px holes in
    /// ragged silhouettes inflate genus). Default on; clamps to the cross-scale-stable hole count.
    pub stable_genus: bool,
}

impl Default for VisionConfig {
    fn default() -> Self {
        VisionConfig {
            fg_thresh: 22.0,
            bg_alpha: 0.04,
            warmup: 8,
            min_area_frac: 0.002,
            max_area_frac: 0.6,
            morph_r: 1,
            compensate: true,
            stable_genus: true,
        }
    }
}

/// A detected object proposal, in resolution-independent normalised coordinates ([0,1], origin
/// top-left). Carries a silhouette crop at work resolution for reconstruction.
#[derive(Clone)]
pub struct Proposal {
    pub cx: f32,
    pub cy: f32,
    pub bw: f32,
    pub bh: f32,
    pub area: f32,
    pub genus: u32,
    /// 8x8 luma appearance signature of the bbox region (for cross-frame association).
    pub sig: [u8; 64],
    /// Silhouette crop (1 = object) at work resolution.
    pub mask: Vec<u8>,
    pub mw: u32,
    pub mh: u32,
    /// Work-resolution bbox (for cropping/recon); pixels.
    pub bx0: u32,
    pub by0: u32,
}

fn erode(m: &[u8], w: usize, h: usize) -> Vec<u8> {
    let mut o = vec![0u8; w * h];
    for y in 0..h {
        for x in 0..w {
            let mut keep = 1u8;
            'k: for dy in -1i32..=1 {
                for dx in -1i32..=1 {
                    let nx = x as i32 + dx;
                    let ny = y as i32 + dy;
                    if nx < 0 || ny < 0 || nx >= w as i32 || ny >= h as i32 || m[ny as usize * w + nx as usize] == 0 {
                        keep = 0;
                        break 'k;
                    }
                }
            }
            o[y * w + x] = keep;
        }
    }
    o
}

fn dilate(m: &[u8], w: usize, h: usize) -> Vec<u8> {
    let mut o = vec![0u8; w * h];
    for y in 0..h {
        for x in 0..w {
            let mut hit = 0u8;
            'k: for dy in -1i32..=1 {
                for dx in -1i32..=1 {
                    let nx = x as i32 + dx;
                    let ny = y as i32 + dy;
                    if nx >= 0 && ny >= 0 && nx < w as i32 && ny < h as i32 && m[ny as usize * w + nx as usize] != 0 {
                        hit = 1;
                        break 'k;
                    }
                }
            }
            o[y * w + x] = hit;
        }
    }
    o
}

/// Count enclosed holes (background regions not reachable from the border) within a sub-mask —
/// the first Betti number / genus proxy, same method as the MAPS reconstructor.
fn hole_count(mask: &[u8], w: usize, h: usize) -> u32 {
    if w == 0 || h == 0 {
        return 0;
    }
    let n = w * h;
    let mut bg = vec![0u8; n];
    let mut st: Vec<usize> = Vec::new();
    let push = |p: usize, bg: &mut [u8], st: &mut Vec<usize>| {
        if mask[p] == 0 && bg[p] == 0 {
            bg[p] = 1;
            st.push(p);
        }
    };
    for x in 0..w {
        push(x, &mut bg, &mut st);
        push((h - 1) * w + x, &mut bg, &mut st);
    }
    for y in 0..h {
        push(y * w, &mut bg, &mut st);
        push(y * w + w - 1, &mut bg, &mut st);
    }
    while let Some(p) = st.pop() {
        let x = p % w;
        let y = p / w;
        let neigh = [
            (x as i32 + 1, y as i32),
            (x as i32 - 1, y as i32),
            (x as i32, y as i32 + 1),
            (x as i32, y as i32 - 1),
        ];
        for (nx, ny) in neigh {
            if nx >= 0 && ny >= 0 && nx < w as i32 && ny < h as i32 {
                push(ny as usize * w + nx as usize, &mut bg, &mut st);
            }
        }
    }
    // Label the unreached background pockets; each is one hole.
    let mut seen = vec![0u8; n];
    let mut holes = 0u32;
    for s in 0..n {
        if mask[s] == 0 && bg[s] == 0 && seen[s] == 0 {
            holes += 1;
            seen[s] = 1;
            let mut q = vec![s];
            while let Some(p) = q.pop() {
                let x = p % w;
                let y = p / w;
                let neigh = [
                    (x as i32 + 1, y as i32),
                    (x as i32 - 1, y as i32),
                    (x as i32, y as i32 + 1),
                    (x as i32, y as i32 - 1),
                ];
                for (nx, ny) in neigh {
                    if nx >= 0 && ny >= 0 && nx < w as i32 && ny < h as i32 {
                        let np = ny as usize * w + nx as usize;
                        if mask[np] == 0 && bg[np] == 0 && seen[np] == 0 {
                            seen[np] = 1;
                            q.push(np);
                        }
                    }
                }
            }
        }
    }
    holes
}

/// Downsample a binary mask by a factor `k` using majority occupancy (a cell is set if >= half
/// of its k*k source pixels are set). Real holes (larger than k*k) survive; 1-2px noise holes
/// get filled and vanish.
fn downsample_mask(m: &[u8], w: usize, h: usize, k: usize) -> (Vec<u8>, usize, usize) {
    let ow = (w / k).max(1);
    let oh = (h / k).max(1);
    let mut o = vec![0u8; ow * oh];
    let half = (k * k + 1) / 2;
    for oy in 0..oh {
        for ox in 0..ow {
            let mut cnt = 0usize;
            for dy in 0..k {
                let sy = oy * k + dy;
                if sy >= h {
                    break;
                }
                for dx in 0..k {
                    let sx = ox * k + dx;
                    if sx >= w {
                        break;
                    }
                    cnt += m[sy * w + sx] as usize;
                }
            }
            o[oy * ow + ox] = (cnt >= half) as u8;
        }
    }
    (o, ow, oh)
}

/// Cross-scale-stable genus: a real hole persists when the mask is downsampled; noise holes (1-2px
/// gaps in a ragged silhouette) vanish at coarser scales. Recompute `hole_count` at scales 1,2,3
/// and take the minimum across scales for which the mask is still meaningfully sized — that is the
/// count that survives, the stable genus.
fn stable_hole_count(mask: &[u8], w: usize, h: usize) -> u32 {
    let g1 = hole_count(mask, w, h);
    if g1 == 0 || w < 8 || h < 8 {
        return g1;
    }
    let mut stable = g1;
    for k in [2usize, 3] {
        if w / k < 4 || h / k < 4 {
            break;
        }
        let (dm, dw, dh) = downsample_mask(mask, w, h, k);
        stable = stable.min(hole_count(&dm, dw, dh));
        if stable == 0 {
            break;
        }
    }
    stable
}

/// Detect proposals in `frame`, updating the background model. Returns `(proposals, fg_frac)`
/// where `fg_frac` is the total foreground fraction (a camera-motion / over-segmentation signal).
pub fn detect(frame: &Frame, bg: &mut BackgroundModel, cfg: &VisionConfig) -> (Vec<Proposal>, f32) {
    let (luma, w, h) = downsample_luma(frame);

    // Estimate dominant global (camera) motion from the previous frame and compensate the
    // background model by warping it into the current frame, so only RESIDUAL (object) motion
    // survives as foreground. A panning camera otherwise lights up the whole frame.
    let motion = if cfg.compensate && bg.prev.len() == w * h {
        estimate_global_motion(&bg.prev, &luma, w, h)
    } else {
        GlobalMotion::IDENTITY
    };

    // Foreground vs background. The EMA mean is a temporal blur that lags an accumulating pan,
    // so under camera motion we instead require a pixel to deviate from BOTH the (motion-warped)
    // background AND the motion-compensated previous frame. Global pan is cancelled by the warp;
    // only residual (object) motion clears both gates. Without compensation, fall back to the
    // plain background diff (static-camera path).
    let mut fg = vec![0u8; w * h];
    let mut fg_count = 0usize;
    if bg.seen > 0 && bg.w == w && bg.h == h {
        // The prev-frame gate is only engaged when a real pan is detected; on a static camera it
        // would wrongly suppress slow-moving objects, so there we keep the pure background model.
        let panning = motion.dx.abs() + motion.dy.abs() > 0.08 || (motion.scale - 1.0).abs() > 0.02;
        if cfg.compensate {
            // Warp the background mean (always) and, under a pan, the previous frame too.
            let model = warp_luma(&bg.mean, w, h, motion);
            let prev_aligned = if panning && bg.prev.len() == w * h {
                Some(warp_luma(&bg.prev, w, h, motion))
            } else {
                None
            };
            for i in 0..w * h {
                let d_bg = (luma[i] - model[i]).abs();
                let pass = match &prev_aligned {
                    // Under a pan, residual motion = deviates from the registered background AND
                    // from the previous frame after pan-compensation (rejects pure global drift).
                    Some(pa) => d_bg > cfg.fg_thresh && (luma[i] - pa[i]).abs() > cfg.fg_thresh,
                    None => d_bg > cfg.fg_thresh,
                };
                if pass {
                    fg[i] = 1;
                    fg_count += 1;
                }
            }
        } else {
            // Static-camera path: plain background difference, the SIMD-accelerated
            // `simd::foreground_diff` kernel (f32x4 abs + compare on wasm+simd128; identical scalar
            // native). Writes the 0/1 mask in place and returns the foreground count.
            fg_count += crate::simd::foreground_diff(&luma, &bg.mean, cfg.fg_thresh, &mut fg);
        }
    }
    // Absorb: warp the EMA state to the current frame so the model tracks the panning scene
    // instead of fighting it, then update toward the new luma.
    if cfg.compensate && bg.w == w && bg.h == h && !bg.mean.is_empty() {
        bg.mean = warp_luma(&bg.mean, w, h, motion);
    }
    bg.update(&luma, w, h, cfg.bg_alpha);
    bg.prev = luma.clone();

    let fg_frac = fg_count as f32 / (w * h) as f32;
    if !bg.ready(cfg.warmup) || fg_frac > cfg.max_area_frac {
        // Warming up, or the whole frame moved (camera pan) — emit nothing this frame.
        return (Vec::new(), fg_frac);
    }

    // Morphological open then close to denoise + fill small gaps.
    for _ in 0..cfg.morph_r {
        fg = erode(&fg, w, h);
    }
    for _ in 0..(cfg.morph_r * 2) {
        fg = dilate(&fg, w, h);
    }
    for _ in 0..cfg.morph_r {
        fg = erode(&fg, w, h);
    }

    // Connected components (8-connectivity).
    let n = w * h;
    let mut label = vec![-1i32; n];
    let mut proposals = Vec::new();
    let min_px = (cfg.min_area_frac * n as f32) as usize;
    let max_px = (cfg.max_area_frac * n as f32) as usize;

    for s in 0..n {
        if fg[s] == 0 || label[s] >= 0 {
            continue;
        }
        let id = proposals.len() as i32;
        let mut stack = vec![s];
        label[s] = id;
        let (mut minx, mut maxx, mut miny, mut maxy) = (w, 0usize, h, 0usize);
        let mut sx = 0u64;
        let mut sy = 0u64;
        let mut count = 0usize;
        while let Some(p) = stack.pop() {
            let x = p % w;
            let y = p / w;
            count += 1;
            sx += x as u64;
            sy += y as u64;
            minx = minx.min(x);
            maxx = maxx.max(x);
            miny = miny.min(y);
            maxy = maxy.max(y);
            for dy in -1i32..=1 {
                for dx in -1i32..=1 {
                    if dx == 0 && dy == 0 {
                        continue;
                    }
                    let nx = x as i32 + dx;
                    let ny = y as i32 + dy;
                    if nx < 0 || ny < 0 || nx >= w as i32 || ny >= h as i32 {
                        continue;
                    }
                    let q = ny as usize * w + nx as usize;
                    if fg[q] != 0 && label[q] < 0 {
                        label[q] = id;
                        stack.push(q);
                    }
                }
            }
        }
        if count < min_px || count > max_px {
            // Roll back this component's id so the next real one is contiguous.
            for v in label.iter_mut() {
                if *v == id {
                    *v = -2; // mark rejected
                }
            }
            continue;
        }

        // Build the silhouette crop + appearance signature.
        let bw_px = maxx - minx + 1;
        let bh_px = maxy - miny + 1;
        let mut mask = vec![0u8; bw_px * bh_px];
        for yy in 0..bh_px {
            for xx in 0..bw_px {
                if label[(miny + yy) * w + (minx + xx)] == id {
                    mask[yy * bw_px + xx] = 1;
                }
            }
        }
        let mut sig = [0u8; 64];
        for cyc in 0..8 {
            for cxc in 0..8 {
                let x0 = minx + cxc * bw_px / 8;
                let x1 = (minx + (cxc + 1) * bw_px / 8).max(x0 + 1).min(w);
                let y0 = miny + cyc * bh_px / 8;
                let y1 = (miny + (cyc + 1) * bh_px / 8).max(y0 + 1).min(h);
                let mut acc = 0f32;
                let mut c = 0f32;
                for yy in y0..y1 {
                    for xx in x0..x1 {
                        acc += luma[yy * w + xx];
                        c += 1.0;
                    }
                }
                sig[cyc * 8 + cxc] = if c > 0.0 { (acc / c) as u8 } else { 0 };
            }
        }

        let genus = if cfg.stable_genus {
            stable_hole_count(&mask, bw_px, bh_px)
        } else {
            hole_count(&mask, bw_px, bh_px)
        };
        proposals.push(Proposal {
            cx: (sx as f32 / count as f32) / w as f32,
            cy: (sy as f32 / count as f32) / h as f32,
            bw: bw_px as f32 / w as f32,
            bh: bh_px as f32 / h as f32,
            area: count as f32 / n as f32,
            genus,
            sig,
            mask,
            mw: bw_px as u32,
            mh: bh_px as u32,
            bx0: minx as u32,
            by0: miny as u32,
        });
    }

    (proposals, fg_frac)
}
